    // x: [N, Cin, Hi, Wi]
    const gert::Shape *x_shape = context->GetInputShape(0);
    // weight: [Cout, Cin, Kh, Kw]
    const gert::Shape *w_shape = context->GetInputShape(1);
    // post_bias: [Cout, 1, 1] (treated as Cout)
    const gert::Shape *pb_shape = context->GetInputShape(3);

    if (x_shape == nullptr || w_shape == nullptr || pb_shape == nullptr) {
        return ge::GRAPH_FAILED;
    }

    const uint32_t N   = static_cast<uint32_t>(x_shape->GetDim(0));
    const uint32_t Cin = static_cast<uint32_t>(x_shape->GetDim(1));
    const uint32_t Hi  = static_cast<uint32_t>(x_shape->GetDim(2));
    const uint32_t Wi  = static_cast<uint32_t>(x_shape->GetDim(3));

    const uint32_t Cout = static_cast<uint32_t>(w_shape->GetDim(0));
    const uint32_t CinW = static_cast<uint32_t>(w_shape->GetDim(1));
    const uint32_t Kh   = static_cast<uint32_t>(w_shape->GetDim(2));
    const uint32_t Kw   = static_cast<uint32_t>(w_shape->GetDim(3));

    // Basic checks
    if (CinW != Cin) {
        return ge::GRAPH_FAILED;
    }

    // stride=1, padding=0, dilation=1
    const uint32_t Ho = (Hi >= Kh) ? (Hi - Kh + 1u) : 0u;
    const uint32_t Wo = (Wi >= Kw) ? (Wi - Kw + 1u) : 0u;

    // conservative block dim based on number of output positions
    const uint64_t totalPos64 = static_cast<uint64_t>(N) * static_cast<uint64_t>(Ho) * static_cast<uint64_t>(Wo);
    uint32_t blockDim = static_cast<uint32_t>(totalPos64 > 0 ? totalPos64 : 1);
    if (blockDim == 0) blockDim = 1;
    if (blockDim > 24u) blockDim = 24u;

    context->SetBlockDim(blockDim);

    tiling.set_N(N);
    tiling.set_Cin(Cin);
    tiling.set_Cout(Cout);
    tiling.set_Hi(Hi);
    tiling.set_Wi(Wi);
    tiling.set_Kh(Kh);
    tiling.set_Kw(Kw);
    tiling.set_Ho(Ho);
    tiling.set_Wo(Wo);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;

    return ge::GRAPH_SUCCESS;
}

