#include <torch/library.h>
#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"

static inline at::Tensor ensure_conv_bias(const at::Tensor& weight, const c10::optional<at::Tensor>& conv_bias_opt) {
    if (conv_bias_opt.has_value()) {
        return conv_bias_opt.value();
    }
    // Create zero bias with shape [Cout]
    auto Cout = weight.size(0);
    return at::zeros({Cout}, weight.options());
}

at::Tensor conv2d_relu_bias_add_impl_npu(const at::Tensor& x,
                                         const at::Tensor& weight,
                                         c10::optional<at::Tensor> conv_bias_opt,
                                         const at::Tensor& post_bias) {
    at::Tensor y = at::empty({x.size(0), weight.size(0),
                              x.size(2) - weight.size(2) + 1,
                              x.size(3) - weight.size(3) + 1}, x.options());
    at::Tensor conv_bias = ensure_conv_bias(weight, conv_bias_opt);
    EXEC_NPU_CMD(aclnnConv2dReluBiasAddCustom, x, weight, conv_bias, post_bias, y);
    return y;
}

